// @vitest-environment node
/**
 * SPEC-040: preguntas ceñidas al guión y a su orden — instrucciones estáticas
 * de adherencia al guión en el prompt de sistema, campo scriptCursor en el
 * schema de structured outputs (acotado y requerido) y realimentación del
 * cursor en el mensaje de usuario (parseo defensivo: el vacío/inválido
 * conserva el último válido), con regresión de la byte-estabilidad SPEC-023 y
 * del encolado SPEC-036/037.
 * Generated by QA Dev agent.
 *
 * Arnés de SPEC-016/021/036/037/038 (SDK y Deepgram mockeados, store y
 * transcriptionService REALES, fake timers solo de Date).
 */
import { mkdtempSync } from 'fs'
import { tmpdir } from 'os'
import { join } from 'path'
import type { WebContents } from 'electron'
import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest'
import {
  MIN_INTERVAL_MS,
  SCRIPT_CURSOR_MAX_CHARS,
  startAssistant,
  stopAssistant
} from '../../../src/main/assistantService'
import * as repository from '../../../src/main/db/repository'
import { initStore } from '../../../src/main/db/store'
import type { DeepgramCallbacks } from '../../../src/main/deepgramService'
import { resetTranscription, startTranscription } from '../../../src/main/transcriptionService'
import type {
  AssistantQueue,
  AssistantUpdateEvent
} from '../../../src/renderer/src/types/assistant'

const harness = vi.hoisted(() => {
  /** Jerarquía espejo de la del SDK: instanceof debe funcionar en mapSdkError. */
  class APIError extends Error {}
  class AuthenticationError extends APIError {}
  class RateLimitError extends APIError {}
  class APIConnectionError extends APIError {}
  return {
    create: vi.fn(),
    dgInstances: [] as unknown[],
    errors: { APIError, AuthenticationError, RateLimitError, APIConnectionError }
  }
})

vi.mock('@anthropic-ai/sdk', () => {
  class MockAnthropic {
    static APIError = harness.errors.APIError
    static AuthenticationError = harness.errors.AuthenticationError
    static RateLimitError = harness.errors.RateLimitError
    static APIConnectionError = harness.errors.APIConnectionError
    readonly messages = { create: harness.create }
  }
  return { default: MockAnthropic }
})

vi.mock('../../../src/main/deepgramService', () => ({
  DeepgramConnection: class {
    apiKey: string
    callbacks: DeepgramCallbacks
    opened = false
    isOpen = false
    sendAudio = vi.fn(() => true)
    sendKeepAlive = vi.fn()
    closeStream = vi.fn()
    terminate = vi.fn()

    constructor(apiKey: string, callbacks: DeepgramCallbacks) {
      this.apiKey = apiKey
      this.callbacks = callbacks
      harness.dgInstances.push(this)
    }
  },
  classifyConnectionFailure: vi.fn(() => Promise.resolve('other' as const))
}))

vi.mock('electron', () => ({
  app: {
    getPath: (): string => {
      throw new Error('app.getPath no debe usarse en tests: initStore recibe baseDir inyectado')
    }
  },
  safeStorage: {
    isEncryptionAvailable: (): boolean => true,
    encryptString: (plain: string): Buffer => Buffer.from(plain, 'utf8'),
    decryptString: (blob: Buffer): string => blob.toString('utf8')
  }
}))

interface FakeConnection {
  callbacks: DeepgramCallbacks
  opened: boolean
  isOpen: boolean
}

/** Parámetros relevantes de una llamada create del asistente. */
interface CreateParams {
  system: unknown
  messages: Array<{ role: string; content: string }>
  output_config: {
    format: {
      type: string
      schema: {
        properties: Record<string, { type?: string; maxLength?: number }>
        required: string[]
      }
    }
  }
}

function createCall(index: number): CreateParams {
  return harness.create.mock.calls[index][0] as CreateParams
}

/** Respuesta del SDK con bloque thinking + bloque text (el JSON va en text). */
function sdkResponse(payload: Record<string, unknown>): unknown {
  return {
    stop_reason: 'end_turn',
    content: [
      { type: 'thinking', thinking: 'razonamiento' },
      { type: 'text', text: JSON.stringify(payload) }
    ]
  }
}

function analysisPayload(overrides: Record<string, unknown> = {}): Record<string, unknown> {
  return {
    action: 'continue',
    suggestedQuestion: '¿Cuándo fue la última vez que pasó?',
    reason: 'Ya hay material concreto para avanzar',
    alarms: [],
    objectivesMet: [],
    resolvedQueueIndexes: [],
    scriptCursor: '',
    ...overrides
  }
}

function createSender(): { sender: WebContents; send: ReturnType<typeof vi.fn> } {
  const send = vi.fn()
  const senderLike = {
    isDestroyed: (): boolean => false,
    send
  }
  return { sender: senderLike as unknown as WebContents, send }
}

function assistantEvents(send: ReturnType<typeof vi.fn>): AssistantUpdateEvent[] {
  return send.mock.calls
    .filter((call) => call[0] === 'assistant:update')
    .map((call) => call[1] as AssistantUpdateEvent)
}

const BASE_TIME_MS = 1_000_000_000

let send: ReturnType<typeof vi.fn>
let connection: FakeConnection
let lineCounter = 0
let analysisCount = 0

function feedFinal(): void {
  lineCounter += 1
  connection.callbacks.onResult({
    channelIndex: lineCounter % 2,
    transcript: `Línea de conversación ${lineCounter}`,
    isFinal: true,
    startSeconds: lineCounter,
    durationSeconds: 1,
    speaker: 0
  })
}

/** Último estado de la cola emitido por main. */
function lastQueue(): AssistantQueue {
  const queue = assistantEvents(send).at(-1)?.queue
  if (queue === undefined) {
    throw new Error('sin eventos del asistente todavía')
  }
  return queue
}

/** Arranca transcripción + asistente; `withScript` controla el guión. */
function startSession(options: { withScript?: boolean } = {}): void {
  const withScript = options.withScript ?? true
  const discovery = repository.createDiscovery({ name: 'Discovery Maurya' })
  const interview = repository.createInterview({
    discoveryId: discovery.id,
    title: 'Entrevista con cursor de guión'
  })
  repository.updateInterview(interview.id, {
    objectives: ['Objetivo cero', 'Objetivo uno'],
    scriptMarkdown: withScript ? '# Guión\n\n## Bloque 1\n\n## Bloque 2 — Presupuesto' : null
  })

  const transcriptionSender = createSender()
  startTranscription(transcriptionSender.sender)
  connection = harness.dgInstances[0] as FakeConnection
  connection.opened = true
  connection.isOpen = true
  connection.callbacks.onOpen()

  const assistantSender = createSender()
  send = assistantSender.send
  startAssistant(assistantSender.sender, interview.id)
}

/** Ejecuta UN análisis completo (ventana de 20 s + 3 líneas + analyzing→active). */
async function analyze(overrides: Record<string, unknown> = {}): Promise<void> {
  analysisCount += 1
  const expectedCalls = analysisCount
  const eventsBefore = assistantEvents(send).length
  harness.create.mockResolvedValueOnce(sdkResponse(analysisPayload(overrides)))
  if (expectedCalls > 1) {
    vi.setSystemTime(BASE_TIME_MS + (expectedCalls - 1) * (MIN_INTERVAL_MS + 1000))
  }
  feedFinal()
  feedFinal()
  feedFinal()
  await vi.waitFor(() => expect(harness.create).toHaveBeenCalledTimes(expectedCalls))
  await vi.waitFor(() => {
    const events = assistantEvents(send)
    expect(events.length).toBeGreaterThanOrEqual(eventsBefore + 2)
    expect(events.at(-1)?.state).toBe('active')
  })
}

/** Texto plano del prompt de sistema (todos los bloques concatenados). */
function systemText(index: number): string {
  const blocks = createCall(index).system as Array<{ text: string }>
  return blocks.map((block) => block.text).join('\n')
}

beforeEach(() => {
  vi.clearAllMocks()
  harness.dgInstances.length = 0
  lineCounter = 0
  analysisCount = 0
  vi.useFakeTimers({ toFake: ['Date'] })
  vi.setSystemTime(BASE_TIME_MS)
  initStore(mkdtempSync(join(tmpdir(), 'maurya-assistant-script-cursor-')))
  process.env['ANTHROPIC_API_KEY'] = 'sk-ant-test'
  process.env['DEEPGRAM_API_KEY'] = 'dg-test'
})

afterEach(() => {
  stopAssistant()
  resetTranscription()
  vi.useRealTimers()
  delete process.env['ANTHROPIC_API_KEY']
  delete process.env['DEEPGRAM_API_KEY']
})

describe('assistantService (cursor de guión SPEC-040)', () => {
  describe('script adherence instructions (system prompt)', () => {
    // SPEC-040 · AC-01 (continue → siguiente pregunta del guión en su orden)
    it('instructs the model to suggest the next uncovered script question in script order on continue', async () => {
      startSession()
      await analyze()

      expect(systemText(0)).toContain(
        'la `suggestedQuestion` debe ser la SIGUIENTE pregunta del guión aún no cubierta, respetando el orden del guión'
      )
    })

    // SPEC-040 · AC-02 (desviación solo Mom Test + volver al guión)
    it('instructs the model to deviate only with Mom Test justification and to return to the script afterwards', async () => {
      startSession()
      await analyze()

      const text = systemText(0)
      expect(text).toContain(
        'Desvíate del guión solo con justificación The Mom Test (falta de evidencia concreta o señal de alarma)'
      )
      expect(text).toContain('vuelve al punto del guión donde te quedaste')
    })

    // SPEC-040 · AC-03 (instrucción del cursor)
    it('instructs the model to return the current script block or question in scriptCursor', async () => {
      startSession()
      await analyze()

      expect(systemText(0)).toContain(
        '`scriptCursor`: el bloque o pregunta del guión que se está tratando ahora mismo'
      )
      expect(systemText(0)).toContain(`máximo ${SCRIPT_CURSOR_MAX_CHARS} caracteres`)
    })
  })

  describe('cursor feedback loop', () => {
    // SPEC-040 · AC-04 (el cursor devuelto viaja en el siguiente mensaje)
    it('feeds the returned cursor back as the current script point in the next user message', async () => {
      startSession()
      await analyze({ scriptCursor: 'Bloque 2 — Presupuesto' })
      await analyze({ suggestedQuestion: '¿Quién decidió esa compra dentro del equipo?' })

      expect(createCall(1).messages[0].content).toContain(
        '## Punto actual del guión\nBloque 2 — Presupuesto'
      )
    })

    // SPEC-040 · AC-05 (sin cursor previo la sección no aparece)
    it('omits the current script point section when no valid cursor was ever returned', async () => {
      startSession()
      await analyze()

      expect(createCall(0).messages[0].content).not.toContain('## Punto actual del guión')
    })

    // SPEC-040 · AC-06 (el cursor vacío conserva el último válido)
    it('keeps the last valid cursor when a later analysis returns an empty one', async () => {
      startSession()
      await analyze({ scriptCursor: 'Bloque 1' })
      await analyze({
        suggestedQuestion: '¿Quién decidió esa compra dentro del equipo?',
        scriptCursor: '   '
      })
      await analyze({ suggestedQuestion: '¿Cuánto tiempo perdisteis la última semana?' })

      expect(createCall(2).messages[0].content).toContain('## Punto actual del guión\nBloque 1')
    })

    // SPEC-040 · AC-07 (tipo inesperado: análisis válido y cursor previo intacto)
    it('keeps the analysis valid and the previous cursor when scriptCursor has an unexpected type', async () => {
      startSession()
      await analyze({ scriptCursor: 'Bloque 1' })
      await analyze({
        suggestedQuestion: '¿Quién decidió esa compra dentro del equipo?',
        scriptCursor: 42
      })

      // El análisis con cursor inválido siguió siendo válido: encoló su candidata
      expect(lastQueue().pending.map((item) => item.suggestedQuestion)).toEqual([
        '¿Quién decidió esa compra dentro del equipo?',
        '¿Cuándo fue la última vez que pasó?'
      ])
      await analyze({ suggestedQuestion: '¿Cuánto tiempo perdisteis la última semana?' })
      expect(createCall(2).messages[0].content).toContain('## Punto actual del guión\nBloque 1')
    })
  })

  describe('output contract', () => {
    // SPEC-040 · AC-08 (scriptCursor acotado y requerido; topes previos intactos)
    it('declares scriptCursor as a bounded required string keeping the existing output caps', async () => {
      startSession()
      await analyze()

      const schema = createCall(0).output_config.format.schema
      expect(schema.properties.scriptCursor).toEqual({
        type: 'string',
        maxLength: SCRIPT_CURSOR_MAX_CHARS
      })
      expect(schema.required).toContain('scriptCursor')
      expect(schema.properties.suggestedQuestion.maxLength).toBe(200)
      expect(schema.properties.reason.maxLength).toBe(140)
    })
  })

  describe('regression (SPEC-023/036/037 invariants)', () => {
    // SPEC-040 · AC-09 (el cursor cambia entre llamadas; el prefijo no)
    it('keeps the system blocks byte-identical while the cursor changes across analyses', async () => {
      startSession()
      await analyze({ scriptCursor: 'Bloque 1' })
      await analyze({
        suggestedQuestion: '¿Quién decidió esa compra dentro del equipo?',
        scriptCursor: 'Bloque 2 — Presupuesto'
      })

      expect(JSON.stringify(createCall(1).system)).toBe(JSON.stringify(createCall(0).system))
      expect(JSON.stringify(createCall(0).system)).not.toContain('Punto actual del guión')
    })

    // SPEC-040 · AC-10 (aceptación/supresión intactas con cursor presente)
    it('keeps candidate acceptance and similarity suppression untouched when a cursor is returned', async () => {
      startSession()
      await analyze({
        suggestedQuestion: '¿Cuánto pagasteis por la última herramienta que comprasteis?',
        scriptCursor: 'Bloque 1'
      })
      // Casi idéntica → suprimida exactamente igual que sin cursor (SPEC-037)
      await analyze({
        suggestedQuestion: '¿Cuánto pagasteis por esa herramienta que comprasteis la última vez?',
        scriptCursor: 'Bloque 1'
      })

      expect(lastQueue().pending.map((item) => item.suggestedQuestion)).toEqual([
        '¿Cuánto pagasteis por la última herramienta que comprasteis?'
      ])
    })

    // SPEC-040 · AC-11 (entrevista sin guión: todo funciona igual)
    it('works unchanged for an interview without script', async () => {
      startSession({ withScript: false })
      await analyze({ scriptCursor: 'algo que el modelo devolvió igualmente' })

      expect(assistantEvents(send).at(-1)?.state).toBe('active')
      expect(lastQueue().pending).toHaveLength(1)
      await analyze({ suggestedQuestion: '¿Quién decidió esa compra dentro del equipo?' })
      expect(createCall(1).messages[0].content).toContain(
        '## Punto actual del guión\nalgo que el modelo devolvió igualmente'
      )
    })
  })
})
